"use strict";(globalThis.webpackChunkwebsite=globalThis.webpackChunkwebsite||[]).push([[4001],{8883(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"first-blog-post","metadata":{"permalink":"/gradgen/blog/first-blog-post","editUrl":"https://github.com/QUB-ASL/gradgen/tree/main/docs/website/blog/2026-03-31-first-blog-post.md","source":"@site/blog/2026-03-31-first-blog-post.md","title":"Gradgen revival","description":"Welcome to this brand new website of gradgen: your Python module for automatic differentiation and truly embedded Rust code generation.","date":"2026-03-31T00:00:00.000Z","tags":[{"inline":false,"label":"New version","permalink":"/gradgen/blog/tags/new_version","description":"Release of new version"}],"readingTime":0.65,"hasTruncateMarker":true,"authors":[{"name":"Pantelis Sopasakis","title":"Lecturer, QUB","url":"https://github.com/alphaville","page":{"permalink":"/gradgen/blog/authors/pantelis"},"imageURL":"https://www.qub.ac.uk/schools/media/Media1218037smxx.png","key":"pantelis"}],"frontMatter":{"slug":"first-blog-post","title":"Gradgen revival","authors":["pantelis"],"tags":["release"]},"unlisted":false},"content":"Welcome to this brand new website of gradgen: your Python module for automatic differentiation and truly embedded Rust code generation.\\n\\nGradgen v0.3 brings two significant changes:\\n\\n1. It has been redesigned to generate **Rust crates**, optionally marked with `#[no_std]` so you can use them directly in your embedded applications\\n2. It comes with specialised code generation mechanisms for **optimal control** leading to Rust code that **does not increase in size** with the prediction horizon\\n\\n\x3c!-- truncate --\x3e\\n\\nWe are already working on gradgen v0.3 which will bring one more significant change: support for high-order functions like **map**, **zip**, and **reduce**, which will improve code generation even more. \\n\\nOur goal is to exploit the structure of a function, its gradient, and Hessian to generate more efficient, elegant, and fast Rust code."}]}}')}}]);